export const QUESTIONS = [{"id":"24hAdyMYYJOI3d680PVZ","type":"objective","question":"Imagine your friend says, 'My dad is going to kill me when he sees my broken phone!' Why is this statement a hyperbole?","options":["Because it is a literal warning that the dad is dangerous.","Because it compares the dad to an angry lion using 'like' or 'as'.","Because it exaggerates the dad's expected anger to emphasize how upset he will be.","Because it is a metaphor that compares a phone to a life."],"answerIndex":2,"answer":null,"explanation":["This is a hyperbole because it uses extreme exaggeration to emphasize how angry or upset the father will be, rather than stating a literal truth."],"hint":"Will the dad actually end the friend's life, or is it an exaggeration?","image":null,"video":"https://youtu.be/iLw5DSyYsaI?si=efDEgzzFGz_rYUo5","videoScope":"set","topic":"Figurative speech","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"4IzaNPTPbM7Jcl724Hao","type":"polar","question":"According to the video, we still use the words 'like' or 'as' when writing a metaphor.","options":["True","False"],"answerIndex":1,"answer":null,"explanation":["The video explicitly states: 'In a metaphor we don't use like or as; we simply say that one thing is another.'"],"hint":"Think about the main difference between a simile and a metaphor.","image":null,"video":"https://youtu.be/iLw5DSyYsaI?si=efDEgzzFGz_rYUo5","videoScope":"set","topic":"Figurative speech","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"63cBzpcc1Sb36GLh9l2f","type":"polar","question":"According to the video, metaphors highlight the relationship between two entirely unrelated things.","options":["True","False"],"answerIndex":0,"answer":null,"explanation":["The video states that metaphors highlight the relationship between two unrelated things to help explain a concept."],"hint":"Think about how a metaphor connects two different concepts.","image":null,"video":"https://youtu.be/iLw5DSyYsaI?si=efDEgzzFGz_rYUo5","videoScope":"set","topic":"Figurative speech","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"6mm3vop4hc0AAcEl9xLq","type":"polar","question":"According to the video, a metaphor is a literal statement that provides an exact, scientific truth about the things being compared.","options":["True","False"],"answerIndex":1,"answer":null,"explanation":["The video explicitly states that a metaphor is not literal, but rather a way to help us express ourselves better."],"hint":"Think about whether metaphors are meant to be taken literally.","image":null,"video":"https://youtu.be/iLw5DSyYsaI?si=efDEgzzFGz_rYUo5","videoScope":"set","topic":"Figurative speech","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"7VcMRACbnGKEFtmguarM","type":"objective","question":"Based on the video, when people use the metaphor 'life is a roller coaster,' what real-life concept are they trying to communicate?","options":["Life moves incredibly fast and is always scary.","Life is full of good times as well as bad.","Life is short and we must visit amusement parks.","Life is controlled by track rails and machinery."],"answerIndex":1,"answer":null,"explanation":["The video explains that 'life is a roller coaster' is used to say that life is full of good times (ups) as well as bad times (downs)."],"hint":"Think about the ups and downs of a roller coaster ride.","image":null,"video":"https://youtu.be/iLw5DSyYsaI?si=efDEgzzFGz_rYUo5","videoScope":"set","topic":"Figurative speech","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"8rxGDN9K483Aj35Ep7kf","type":"subjective","question":"According to the video, writers use figures of speech like similes, metaphors, and hyperboles to make their stories more ____ and exciting.","options":null,"answerIndex":null,"answer":"interesting","explanation":["The video states that these are tools writers use to make their stories more interesting and exciting."],"hint":"","image":null,"video":"https://youtu.be/iLw5DSyYsaI?si=efDEgzzFGz_rYUo5","videoScope":"set","topic":"Figurative speech","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"AeUse1HkydKOfNqfkOF3","type":"objective","question":"Which of the following options correctly pairs a figure of speech with its correct definition based on the video?","options":["Simile: A figure of speech that exaggerates a situation to make it funny.","Metaphor: A comparison between two things using 'like' or 'as'.","Hyperbole: A figure of speech that exaggerates a situation, quality, or characteristic to emphasize it.","Metaphor: A literal description that avoids any comparison."],"answerIndex":2,"answer":null,"explanation":["The video defines hyperbole as 'a figure of speech that exaggerates a situation, quality, or characteristic to emphasize it.' Metaphors do not use 'like' or 'as', and similes do."],"hint":"Recall the definition of hyperbole given in the video.","image":null,"video":"https://youtu.be/iLw5DSyYsaI?si=efDEgzzFGz_rYUo5","videoScope":"set","topic":"Figurative speech","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"CIcNIO5N7uxA36KGslgC","type":"short","question":"In the video, the narrator explains that their friends say they are 'as clever as a fox.' What specific skill makes their friends say this?","options":null,"answerIndex":null,"answer":"solving math problems","explanation":["The narrator says friends call them 'as clever as a fox' because they are really good at solving math problems."],"hint":"The narrator mentions being really good at a school subject.","image":null,"video":"https://youtu.be/iLw5DSyYsaI?si=efDEgzzFGz_rYUo5","videoScope":"set","topic":"Figurative speech","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"Gc9FxzKMrDdtAbrgqGlB","type":"objective","question":"Which of the following sentences is a simile?","options":["The bright sun was a golden coin in the sky.","My sister slept like a baby after the long journey.","I have been waiting for you for a million years!","The computer is a brain that stores our secrets."],"answerIndex":1,"answer":null,"explanation":["Sentence 2 uses 'like' to compare how the sister slept to a baby, making it a simile. The others are metaphors or hyperboles."],"hint":"Look for the comparison words 'like' or 'as'.","image":null,"video":"https://youtu.be/iLw5DSyYsaI?si=efDEgzzFGz_rYUo5","videoScope":"set","topic":"Figurative speech","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"IIWD4pH4yauOBWXVB1s2","type":"subjective","question":"At the very end of the video, the narrator uses an encouraging phrase to describe the possibilities of using your words, saying, 'The ____ is the limit.'","options":null,"answerIndex":null,"answer":"sky","explanation":["The video closes with the encouraging idiom/hyperbole: 'When it comes to your words, the sky is the limit.'"],"hint":"","image":null,"video":"https://youtu.be/iLw5DSyYsaI?si=efDEgzzFGz_rYUo5","videoScope":"set","topic":"Figurative speech","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"IxK4IOxuhe6PK0PI9Zio","type":"subjective","question":"When a speaker exaggerates a situation to emphasize a point, such as saying they are so hungry they could eat a horse, they are using a figure of speech called ____.","options":null,"answerIndex":null,"answer":"hyperbole","explanation":["Hyperbole is a figure of speech that uses extreme exaggeration to make a point or emphasize a characteristic."],"hint":"","image":null,"video":"https://youtu.be/iLw5DSyYsaI?si=efDEgzzFGz_rYUo5","videoScope":"set","topic":"Figurative speech","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"N7gD6iqYezPhaP0eqifZ","type":"short","question":"Following the pattern in the video where the simile 'Peter is as tall as a giant' is changed into the metaphor 'Peter is a giant', rewrite the simile 'The runner was as fast as lightning' into a metaphor.","options":null,"answerIndex":null,"answer":"The runner was lightning","explanation":["To turn the simile into a metaphor, we remove 'as fast as' and directly state: 'The runner was lightning'."],"hint":"Remove the comparison words 'as... as' to state directly what the runner was.","image":null,"video":"https://youtu.be/iLw5DSyYsaI?si=efDEgzzFGz_rYUo5","videoScope":"set","topic":"Figurative speech","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"PqZTvTLZBbMZS3DnF6UJ","type":"polar","question":"The sentence 'The ocean roared with anger during the storm' is an example of a simile because it compares the ocean to an angry person.","options":["True","False"],"answerIndex":1,"answer":null,"explanation":["This is false. A simile must use 'like' or 'as'. This sentence does not use either, so it is not a simile."],"hint":"Does the sentence use 'like' or 'as' to make the comparison?","image":null,"video":"https://youtu.be/iLw5DSyYsaI?si=efDEgzzFGz_rYUo5","videoScope":"set","topic":"Figurative speech","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"QDSYoioXSZxaRxjiNEgJ","type":"objective","question":"Consider these two sentences: <br>1. 'The dancer was as graceful as a swan.'<br>2. 'The dancer was a graceful swan on stage.'<br>How do these sentences differ in their use of figurative language?","options":["Sentence 1 is a metaphor because it uses 'as', while Sentence 2 is a simile.","Sentence 1 is a simile because it uses 'as', while Sentence 2 is a metaphor because it directly states the dancer was a swan.","Sentence 1 is a hyperbole because it exaggerates, while Sentence 2 is a literal statement.","Both sentences are similes because they both compare a dancer to a swan."],"answerIndex":1,"answer":null,"explanation":"Sentence 1 uses 'as... as' to make a comparison (simile). Sentence 2 directly calls the dancer a swan without 'like' or 'as' (metaphor).","hint":"Remember that similes use 'like' or 'as', while metaphors state that one thing IS another.","image":null,"video":"https://youtu.be/iLw5DSyYsaI?si=efDEgzzFGz_rYUo5","videoScope":"set","topic":"Figurative speech","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"Tm7GYBXyUvHEeeVtFbPR","type":"polar","question":"When the narrator in the video says they have been told they 'sleep like a baby,' it means they sleep very soundly.","options":["True","False"],"answerIndex":0,"answer":null,"explanation":["The narrator states: 'I've been told many times that I sleep like a baby because I sleep very soundly.'"],"hint":"Does a baby sleep soundly, or is it a noisy sleeper?","image":null,"video":"https://youtu.be/iLw5DSyYsaI?si=efDEgzzFGz_rYUo5","videoScope":"set","topic":"Figurative speech","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"a2VlmFC5yXyvPFF1LCuz","type":"short","question":"What specific animal is used in the video's example of a simile to describe someone who is very stubborn?","options":null,"answerIndex":null,"answer":"mule","explanation":["The video mentions the common expression 'stubborn as a mule' as an example of a simile."],"hint":"This animal is known for refusing to move when it doesn't want to.","image":null,"video":"https://youtu.be/iLw5DSyYsaI?si=efDEgzzFGz_rYUo5","videoScope":"set","topic":"Figurative speech","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"nNeIaTiCVYOIozH3BOH3","type":"objective","question":"In the sentence 'The classroom was a zoo during recess,' what type of figurative language is used, and what does it mean?","options":["It is a simile, meaning there were actual wild animals in the classroom.","It is a metaphor, meaning the classroom was very noisy and chaotic.","It is a hyperbole, meaning the teacher bought animals for the class.","It is a metaphor, meaning the students were learning about biology."],"answerIndex":1,"answer":null,"explanation":["This is a metaphor because it directly compares the classroom to a zoo without using 'like' or 'as'. It describes a chaotic, noisy environment."],"hint":"Think about whether 'like' or 'as' is used, and what a zoo is typically like.","image":null,"video":"https://youtu.be/iLw5DSyYsaI?si=efDEgzzFGz_rYUo5","videoScope":"set","topic":"Figurative speech","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"s5TLD8lLcnppSAPJqCYx","type":"objective","question":"Read this sentence: 'My schoolbag weighs a ton!' Which figure of speech is the writer using, and what is its purpose?","options":["Simile, to show that the bag is exactly 1,000 kilograms.","Metaphor, to compare the bag directly to a heavy metal weight.","Hyperbole, to exaggerate how heavy the bag feels to emphasize that it is very heavy.","Hyperbole, to prove that the student has super strength."],"answerIndex":2,"answer":null,"explanation":["The speaker is using hyperbole. It is an exaggeration used to emphasize how heavy the bag feels, not a literal weight."],"hint":"Is the bag literally a ton (1,000 kg), or is the speaker exaggerating?","image":null,"video":"https://youtu.be/iLw5DSyYsaI?si=efDEgzzFGz_rYUo5","videoScope":"set","topic":"Figurative speech","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"xf3mqExkTlqrRlImTnlZ","type":"subjective","question":"When someone says 'I've been waiting for you forever,' they are using hyperbole. This means they have actually been waiting for a very ____ time, not literally since the beginning of time.","options":null,"answerIndex":null,"answer":"long","explanation":["The video explains that 'waiting forever' is a hyperbole meaning the person has been waiting for a very, very long time."],"hint":"","image":null,"video":"https://youtu.be/iLw5DSyYsaI?si=efDEgzzFGz_rYUo5","videoScope":"set","topic":"Figurative speech","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"yC0LcsSoMRechr8vMHE9","type":"short","question":"Based on the video, what real-world concept are people describing when they use the metaphor 'time is money'?","options":null,"answerIndex":null,"answer":"how precious time is","explanation":["The video notes that people say 'time is money' to express 'how precious time is'."],"hint":"Think about why we compare time to something valuable like money.","image":null,"video":"https://youtu.be/iLw5DSyYsaI?si=efDEgzzFGz_rYUo5","videoScope":"set","topic":"Figurative speech","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"0qDfDWytYl1FBkDJTYlr","type":"objective","question":"Which sentence uses the preposition correctly?","options":["He is afraid *from* spiders.","He is afraid *about* spiders.","He is afraid *of* spiders.","He is afraid *with* spiders."],"answerIndex":2,"answer":null,"explanation":["The correct phrase is 'afraid of' to express fear or apprehension."],"hint":"Some adjectives are always followed by a specific preposition.","image":null,"video":null,"videoScope":"question","topic":"preposition","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"5U2QMX7zLRiMod30SFia","type":"polar","question":"True or False: A preposition can tell us *where* something is located.","options":["True","False"],"answerIndex":0,"answer":null,"explanation":["Prepositions often show place or position, like 'under', 'in', 'behind', 'on', 'at'."],"hint":"","image":null,"video":null,"videoScope":"question","topic":"preposition","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"697xj4ETfaTe9LcoXFiU","type":"subjective","question":"The children jumped ____ the swimming pool with a big splash.","options":null,"answerIndex":null,"answer":"into","explanation":["'Into' shows movement from outside to inside a place."],"hint":"","image":null,"video":null,"videoScope":"question","topic":"preposition","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"DniduQvhr8SOlN0UlSB4","type":"objective","question":"Which word in the sentence below is a preposition?\\n\\n\"The little squirrel ran *up* the tree quickly.\"","options":["little","ran","up","quickly"],"answerIndex":2,"answer":null,"explanation":["'Up' shows the direction the squirrel moved in relation to the tree."],"hint":"Think about words that show position or direction.","image":null,"video":null,"videoScope":"question","topic":"preposition","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"Ui0ICiwMVLo6x4zoKgno","type":"polar","question":"True or False: Prepositions can only tell us about time and place, not about how something is done.","options":["True","False"],"answerIndex":1,"answer":null,"explanation":["False. Prepositions can also show how something is done (e.g., 'He writes *with* a pen'), the cause of something (e.g., 'She cried *out of* joy'), or possession (e.g., 'the book *of* stories')."],"hint":"","image":null,"video":null,"videoScope":"question","topic":"preposition","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"WV4vLP44bOkhsrOLSXlW","type":"subjective","question":"Write a short sentence (5-8 words) using the preposition \"under\" to describe where something is.","options":null,"answerIndex":null,"answer":"The cat slept under the warm blanket.","explanation":["'Under' indicates a position below something else."],"hint":"","image":null,"video":null,"videoScope":"question","topic":"preposition","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"albaZdY7U5Qlv6Yahhfx","type":"short","question":"What is the main job of a preposition in a sentence?","options":null,"answerIndex":null,"answer":"To show the relationship between a noun/pronoun and other words (e.g., position, time, direction).","explanation":["Prepositions connect nouns or pronouns to other parts of the sentence, showing how they relate to each other."],"hint":"","image":null,"video":null,"videoScope":"question","topic":"preposition","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"esPuAgOy2HYj1NhCkVmN","type":"objective","question":"Choose the best prepositions to complete the sentence:\\n\\nWe play football ____ the park ____ Saturdays.","options":["at, in","in, on","on, at","by, for"],"answerIndex":1,"answer":null,"explanation":["'In' is used for general enclosed spaces like a park. 'On' is used for specific days of the week."],"hint":"Think about prepositions for general locations and specific days.","image":null,"video":null,"videoScope":"question","topic":"preposition","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"pdfcdkkRseKZG9mPlpR1","type":"subjective","question":"Complete the sentence with the most suitable preposition:\\n\\nThe book is ____ the table, right next to the lamp.","options":null,"answerIndex":null,"answer":"on","explanation":["'On' indicates that the book is resting on the surface of the table."],"hint":"","image":null,"video":null,"videoScope":"question","topic":"preposition","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"zChlIzBy4n92io68HiJr","type":"theory","question":"Explain the difference in meaning between these two sentences:\\n\\n1. \"She walked *past* the shop.\"\\n2. \"She walked *to* the shop.\"","options":null,"answerIndex":null,"answer":"In sentence 1, \"She walked past the shop\" means she walked by the shop without stopping or going inside, moving beyond its location. In sentence 2, \"She walked to the shop\" means she walked with the intention of reaching the shop as her destination.","explanation":["'Past' indicates moving by something. 'To' indicates movement towards a destination."],"hint":"","image":null,"video":null,"videoScope":"question","topic":"preposition","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"2EQzGvGzL2RfJFxcJY6n","type":"subjective","question":"Please make sure you submit your science project ____ Friday afternoon at the very latest, as late entries will not be graded.","options":null,"answerIndex":null,"answer":"by","explanation":["The preposition 'by' is used to show a deadline or a point in time by which something must be completed.","Using 'on' would mean specifically on Friday afternoon, but 'by' highlights the limit/deadline."],"hint":"We need a preposition of time that means 'not later than' or 'at or before'.","image":null,"video":null,"videoScope":"question","topic":"preposition","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"4dMnkiBfZWdcM6F3bnmg","type":"short","question":"Identify the preposition of time in this sentence: 'We must finish our breakfast before eight o'clock.'","options":null,"answerIndex":null,"answer":"before","explanation":["'Before' is a preposition of time indicating that the action must happen prior to eight o'clock."],"hint":"Look for the word that connects the action of eating breakfast to a specific time on the clock.","image":null,"video":null,"videoScope":"question","topic":"preposition","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"6GRMRlYa7H3N2R8oFIN0","type":"subjective","question":"The keys were not on the dining table; instead, Sarah found them hiding ____ a heavy book on the shelf, completely out of sight.","options":null,"answerIndex":null,"answer":"under","explanation":["'Under' (or 'beneath' / 'underneath') is the correct preposition of place here because the keys were covered or hidden by the book.","'Under' is the most common and appropriate answer."],"hint":"The keys were covered by the heavy book.","image":null,"video":null,"videoScope":"question","topic":"preposition","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"7fAxbUPiFNmVad7Ram3A","type":"short","question":"Identify the incorrect preposition in this sentence and write the correct one that should replace it: 'The teacher shared the box of chocolates between all the thirty students in the class.'","options":null,"answerIndex":null,"answer":"among","explanation":["We use 'between' when referring to two distinct people or things.","We use 'among' when referring to a group of three or more people or things."],"hint":"Think about which preposition we use when sharing things with more than two people.","image":null,"video":null,"videoScope":"question","topic":"preposition","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"KXw3e9iRVkefdFm9oxzg","type":"polar","question":"In the sentence 'The energetic dog jumped over the wooden fence', the word 'over' is a preposition of movement.","options":["True","False"],"answerIndex":0,"answer":null,"explanation":["The word 'over' is a preposition of movement (or direction) because it describes the path of the dog's jump from one side of the fence to the other."],"hint":"Does 'over' show the direction or path of the dog's action?","image":null,"video":null,"videoScope":"question","topic":"preposition","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"PcXH9hbwYK340pq4rdfy","type":"objective","question":"The hikers had to walk cautiously ____ the narrow, dark tunnel to reach the other side of the mountain.","options":["through","across","along","into"],"answerIndex":0,"answer":null,"explanation":["'Through' is used for movement inside an enclosed, three-dimensional space like a tunnel, forest, or pipe.","'Across' is used for flat surfaces, and 'along' is for following a line."],"hint":"Which preposition is used when moving from one end of a three-dimensional enclosed space to the other?","image":null,"video":null,"videoScope":"question","topic":"preposition","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"bmJhHUVK3Q4bHkhiOLsE","type":"objective","question":"The principal warmly congratulated the students ____ winning the national spelling bee championship.","options":["for","on","at","about"],"answerIndex":1,"answer":null,"explanation":["The verb 'congratulate' is followed by the preposition 'on' when referring to the achievement (e.g., 'congratulate someone on something').","While 'for' is commonly used in speech, 'on' is grammatically correct."],"hint":"Think about the specific preposition that always follows the verb 'congratulate'.","image":null,"video":null,"videoScope":"question","topic":"preposition","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"hb4ig5AIpawBwd6NIrUS","type":"polar","question":"In the sentence 'According to the news, the school will be closed tomorrow due to heavy snow', the phrase 'According to' functions as a preposition.","options":["True","False"],"answerIndex":0,"answer":null,"explanation":["Yes, 'According to' is a multi-word or complex preposition. It introduces the noun phrase 'the news' to show the source of information."],"hint":"Can prepositions consist of more than one word?","image":null,"video":null,"videoScope":"question","topic":"preposition","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"lLNY7YdRLh3rm4kF7lN5","type":"objective","question":"Identify the sentence that uses prepositions correctly.","options":["We arrived to the train station just in time.","My sister is very good in drawing portraits.","The little boy is terrified of spiders.","I am angry on you for losing my favorite book."],"answerIndex":2,"answer":null,"explanation":["Option 1 should be 'arrived at the train station'.","Option 2 should be 'good at drawing'.","Option 3 is correct because 'terrified' is paired with 'of'.","Option 4 should be 'angry with you'."],"hint":"Look closely at the adjectives and verbs paired with their prepositions (e.g., 'good', 'terrified', 'angry', 'arrived').","image":null,"video":null,"videoScope":"question","topic":"preposition","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"m4dDMtx9JbIw0T3iEDFn","type":"theory","question":"Explain the difference in meaning between these two sentences:\\n1) 'She is in the school.'\\n2) 'She is at the school.'","options":null,"answerIndex":null,"answer":"'In the school' means she is physically inside the school building. 'At the school' is more general and means she is at that location (such as in the playground, near the gates, or attending as a student), but not necessarily inside the building structure itself.","explanation":["'In' emphasizes being enclosed within the physical walls of a building.","'At' refers to a specific point, location, or institution."],"hint":"Think about physical boundaries versus a general location.","image":null,"video":null,"videoScope":"question","topic":"preposition","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"57lj3c23Ndhpc48lRxly","type":"subjective","question":"Complete the sentence with the best preposition: 'The children played happily ____ the garden.'","options":null,"answerIndex":null,"answer":"in","explanation":["We use 'in' to describe being inside an enclosed area like a garden."],"hint":"Consider what preposition is used for enclosed spaces.","image":null,"video":null,"videoScope":"question","topic":"preposition","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"DHGhBs0fakSH3rdVhgUF","type":"subjective","question":"Fill in the blank: 'My friend lives ____ the blue house next to the park.'","options":null,"answerIndex":null,"answer":"in","explanation":["We use 'in' to describe someone residing inside a building or house."],"hint":"What preposition do you use when someone lives inside a building?","image":null,"video":null,"videoScope":"question","topic":"preposition","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"Gpy1SanWlplS38K004Ip","type":"short","question":"What is the preposition in this phrase: 'walking *towards* the school'?","options":null,"answerIndex":null,"answer":"towards","explanation":["'Towards' indicates the direction of movement, making it a preposition."],"hint":"The word that shows direction.","image":null,"video":null,"videoScope":"question","topic":"preposition","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"L72rJMcHmKrKWb87cL41","type":"theory","question":"Explain in your own words what a preposition does in a sentence.","options":null,"answerIndex":null,"answer":"A preposition is a word that shows the relationship between a noun or pronoun and another word in the sentence. It often tells us about place, time, or direction.","explanation":["Prepositions are like connecting words that help us understand where, when, or how something is related to something else."],"hint":"Think about what kind of information prepositions usually give us.","image":null,"video":null,"videoScope":"question","topic":"preposition","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"LHEbvapaq4S172cYroiU","type":"polar","question":"True or False: A preposition always comes after a noun.","options":["True","False"],"answerIndex":1,"answer":null,"explanation":["Prepositions usually come *before* a noun or pronoun (e.g., 'under the bed') to show its relationship to another word in the sentence."],"hint":"Think about examples like 'on the table' or 'behind the door'.","image":null,"video":null,"videoScope":"question","topic":"preposition","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"Q4QECdi5jYghrC1EeMf3","type":"objective","question":"Which word in the sentence 'The squirrel hid its nuts *under* the big oak tree' is a preposition?","options":["squirrel","hid","under","tree"],"answerIndex":2,"answer":null,"explanation":["'Under' tells us where the nuts were hidden, showing their position relative to the tree."],"hint":"Think about words that show position or location.","image":null,"video":null,"videoScope":"question","topic":"preposition","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"cnZVQ5BLgAE8HbHHSvU2","type":"subjective","question":"Write a sentence using the preposition 'between' to describe where two objects are.","options":null,"answerIndex":null,"answer":"The ball rolled between the two chairs.","explanation":["'Between' is used to show that something is situated in the middle of two other distinct objects or points."],"hint":"Think about placing something in the middle of two other things.","image":null,"video":null,"videoScope":"question","topic":"preposition","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"pOK25vr0jftEzMQoS4Wp","type":"objective","question":"Choose the correct preposition to complete the sentence: 'The boy climbed ____ the ladder to reach the top.'","options":["over","up","down","around"],"answerIndex":1,"answer":null,"explanation":["'Up' indicates movement to a higher position, which is what you do when climbing a ladder to reach the top."],"hint":"What direction do you usually climb a ladder to go higher?","image":null,"video":null,"videoScope":"question","topic":"preposition","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"pdL4S1F1zDVrcBVoin7C","type":"short","question":"Name one preposition that tells us about time.","options":null,"answerIndex":null,"answer":"at","explanation":["'At' is often used for specific times (e.g., 'at 3 o'clock', 'at night'). Other time prepositions include 'in' (in December), 'on' (on Monday), 'before', 'after', etc."],"hint":"Think about how you'd say 'My birthday is ____ December'.","image":null,"video":null,"videoScope":"question","topic":"preposition","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"zoKLxq4uHB42aSwbJezk","type":"objective","question":"Which sentence uses a preposition incorrectly?","options":["The dog ran *after* the ball.","She is good *at* drawing pictures.","They waited *for* the bus patiently.","He got *on* the car quickly."],"answerIndex":3,"answer":null,"explanation":["We usually say 'He got *into* the car' or 'He got *in* the car'. 'On' is typically used for larger forms of transport like a bus, train, or plane."],"hint":"Think about the common prepositions used with 'car' versus 'bus' or 'train'.","image":null,"video":null,"videoScope":"question","topic":"preposition","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"0PMj8vV4ybvobLNT91g8","type":"theory","question":"Explain the main difference between a common noun and a proper noun. Give one example for each.","options":null,"answerIndex":null,"answer":"A common noun names a general person, place, animal, or thing (e.g., 'boy', 'city'). A proper noun names a specific person, place, animal, or thing and always starts with a capital letter (e.g., 'Tom', 'London').","explanation":["The key difference is specificity and capitalisation. Proper nouns are unique names."],"hint":"","image":null,"video":null,"videoScope":"question","topic":"noun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"59MwiEsCIMPwJN9Uyf5v","type":"polar","question":"The noun 'water' can be counted, so we can say 'two waters'. True or False?","options":["True","False"],"answerIndex":1,"answer":null,"explanation":["'Water' is an uncountable noun. We cannot say 'two waters' (unless referring to different types of water, which is less common). We usually say 'two glasses of water' or 'a lot of water'."],"hint":"","image":null,"video":null,"videoScope":"question","topic":"noun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"JTQBgpzpbIzpT9PGa6zM","type":"short","question":"Rewrite the phrase 'the car belonging to my mother' using a possessive noun.","options":null,"answerIndex":null,"answer":"my mother's car","explanation":["A possessive noun shows ownership, usually formed by adding an apostrophe and 's' ('s) to the noun."],"hint":"","image":null,"video":null,"videoScope":"question","topic":"noun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"Nelqfas5j564RMiaTtl5","type":"objective","question":"Which of these words is an abstract noun?","options":["table","happiness","flower","student"],"answerIndex":1,"answer":null,"explanation":["'Happiness' is a feeling or an idea that cannot be physically touched, making it an abstract noun. 'Table', 'flower', and 'student' are concrete nouns because they name things you can see and touch."],"hint":"Abstract nouns name ideas, feelings, or qualities that you cannot touch or see.","image":null,"video":null,"videoScope":"question","topic":"noun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"Secumi6UkYCcLulOpqFv","type":"subjective","question":"A ____ of bees flew out of the hive.","options":null,"answerIndex":null,"answer":"swarm","explanation":["'Swarm' is a collective noun used to describe a group of bees."],"hint":"","image":null,"video":null,"videoScope":"question","topic":"noun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"iidNyJMS8rwNSQz0xPg0","type":"short","question":"In your own words, what is a noun?","options":null,"answerIndex":null,"answer":"A noun is a word that names a person, place, animal, or thing.","explanation":["Nouns are fundamental building blocks of sentences, giving names to everything around us."],"hint":"","image":null,"video":null,"videoScope":"question","topic":"noun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"pOAesKdUtssaBOSOOAR4","type":"subjective","question":"The children played happily in the school ____ during recess.","options":null,"answerIndex":null,"answer":"playground","explanation":["'Playground' is a noun that names a place where children play, fitting the context of the sentence."],"hint":"","image":null,"video":null,"videoScope":"question","topic":"noun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"rDP71IKIpBLtfCfJ787Q","type":"objective","question":"Which word in the sentence below is a noun? 'The fluffy cat slept soundly on the rug.'","options":["fluffy","slept","cat","soundly"],"answerIndex":2,"answer":null,"explanation":["'Cat' is the name of an animal, making it a noun. 'Fluffy' describes the cat (adjective), 'slept' is an action (verb), and 'soundly' describes how it slept (adverb)."],"hint":"Think about words that name a person, animal, place, or thing.","image":null,"video":null,"videoScope":"question","topic":"noun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"ttsj9FeYgwLgqskVYiXa","type":"polar","question":"A proper noun always starts with a small letter. True or False?","options":["True","False"],"answerIndex":1,"answer":null,"explanation":["Proper nouns, which name specific people, places, or things (e.g., 'Sarah', 'Paris', 'Monday'), always begin with a capital letter."],"hint":"","image":null,"video":null,"videoScope":"question","topic":"noun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"zruXdNNkiLJgpIWb70uD","type":"objective","question":"Which of these words is a common noun?","options":["Singapore","Teacher","Mary","Jupiter"],"answerIndex":1,"answer":null,"explanation":["'Teacher' is a general term for a person, so it's a common noun. 'Singapore', 'Mary', and 'Jupiter' are specific names, making them proper nouns."],"hint":"A common noun names a general type of person, place, or thing.","image":null,"video":null,"videoScope":"question","topic":"noun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"2daw38IaCmEV5O4QzZWS","type":"objective","question":"Which of these words is a **proper noun**?","options":["city","ocean","Singapore","flower"],"answerIndex":2,"answer":null,"explanation":["'Singapore' is a proper noun because it names a specific city. The other words are common nouns."],"hint":"Proper nouns name specific things and are always capitalised.","image":null,"video":null,"videoScope":"question","topic":"noun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"GMc7QMRON4ASaAxjFJhY","type":"subjective","question":"The ____ tail was long and bushy. (fox)","options":null,"answerIndex":null,"answer":"fox's","explanation":["To show possession for a singular noun, we add an apostrophe followed by 's' (e.g., fox's)."],"hint":"You need to show that the tail belongs to the fox. How do we form possessive nouns?","image":null,"video":null,"videoScope":"question","topic":"noun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"PznITvDdrsEC9FgQInh4","type":"subjective","question":"A group of lions is called a ____.","options":null,"answerIndex":null,"answer":"pride","explanation":["'Pride' is the collective noun used to refer to a group of lions."],"hint":"This is a special word for a group of specific animals.","image":null,"video":null,"videoScope":"question","topic":"noun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"TFZd1OHByslkX2WtBZyc","type":"polar","question":"Is 'courage' a concrete noun?","options":["True","False"],"answerIndex":1,"answer":null,"explanation":["'Courage' is an abstract noun because it names an idea or quality that cannot be perceived with the five senses. Concrete nouns name things you can experience with your senses."],"hint":"Can you see, touch, hear, smell, or taste courage?","image":null,"video":null,"videoScope":"question","topic":"noun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"dGSIPo8r7ob7QUsoSkuE","type":"theory","question":"Read the short paragraph below. List three nouns and explain whether each is a common noun or a proper noun.<br><br>\"My family visited the zoo last weekend. We saw many animals, including a huge elephant and a playful monkey. My sister, Lily, bought a souvenir from the gift shop.\"","options":null,"answerIndex":null,"answer":"Example Answer: <br>1. Lily (Proper Noun) - It names a specific person.<br>2. Zoo (Common Noun) - It names a general place.<br>3. Elephant (Common Noun) - It names a general animal.","explanation":["This question assesses your ability to identify different types of nouns within a context and explain their classification."],"hint":"Remember that proper nouns are always capitalised and name specific things, while common nouns name general things.","image":null,"video":null,"videoScope":"question","topic":"noun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"dHrbNhg2NV1fYb2FJ4oK","type":"short","question":"What is the plural form of the noun 'child'?","options":null,"answerIndex":null,"answer":"children","explanation":["'Child' is an irregular noun, and its plural form is 'children', not 'childs'."],"hint":"Some nouns have irregular plural forms.","image":null,"video":null,"videoScope":"question","topic":"noun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"nS75M4C065aqSYOZWGUM","type":"objective","question":"Which of the following best describes a noun?","options":["A word that describes an action.","A word that names a person, place, animal, or thing.","A word that shows strong feeling.","A word that connects two sentences."],"answerIndex":1,"answer":null,"explanation":["Nouns are words used to identify any of a class of people, places, animals, or things, or to name a particular one of these."],"hint":"Think about what nouns are used for.","image":null,"video":null,"videoScope":"question","topic":"noun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"p4nbuiEb4xG4pxAYkQdk","type":"theory","question":"Write one sentence that includes at least one common noun and one abstract noun. Underline both nouns.","options":null,"answerIndex":null,"answer":"Example Answer: The <u>boy</u> showed great <u>kindness</u> to his pet. (<u>boy</u> is common noun, <u>kindness</u> is abstract noun).","explanation":["This question tests your understanding of common and abstract nouns by asking you to apply them in sentence construction."],"hint":"Think of things you can see or touch (common nouns) and qualities or ideas (abstract nouns).","image":null,"video":null,"videoScope":"question","topic":"noun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"sRsczDMPEKtOCCCssjyo","type":"objective","question":"Which of these nouns is typically considered an **uncountable noun**?","options":["apple","chair","water","friend"],"answerIndex":2,"answer":null,"explanation":["'Water' is an uncountable noun because it refers to a substance that cannot be counted individually. We use terms like 'some water' or 'a glass of water'. The other nouns are countable."],"hint":"Can you count 'one of' these things, or do you usually refer to an amount of it?","image":null,"video":null,"videoScope":"question","topic":"noun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"xM8aaEyAQlYhv98ceVhA","type":"short","question":"Identify all the nouns in the following sentence: \"The clever student read a book about space in the library.\"","options":null,"answerIndex":null,"answer":"student, book, space, library","explanation":["'Student' names a person, 'book' names a thing, 'space' names a concept/place, and 'library' names a place."],"hint":"Look for words that name people, objects, ideas, or places.","image":null,"video":null,"videoScope":"question","topic":"noun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"32Ii9ReEaoN3uLdQKLit","type":"objective","question":"Which word is an uncountable noun?","options":["apple","water","book","chair"],"answerIndex":1,"answer":null,"explanation":["Uncountable nouns refer to things that cannot be counted individually. We usually talk about 'some water' or 'a glass of water', not 'one water'."],"hint":"","image":null,"video":null,"videoScope":"question","topic":"noun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"3jpW51AYGyLViCppzW6x","type":"polar","question":"The word 'flower' is a common noun. True or False?","options":["True","False"],"answerIndex":0,"answer":null,"explanation":["'Flower' refers to any flower in general, not a specific one, making it a common noun."],"hint":"","image":null,"video":null,"videoScope":"question","topic":"noun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"AoKJgJrES5lEOUuWjuM0","type":"objective","question":"Which of the following words is a proper noun?","options":["city","Singapore","park","river"],"answerIndex":1,"answer":null,"explanation":["Proper nouns name specific people, places, or things and always begin with a capital letter. 'Singapore' is the specific name of a country/city."],"hint":"","image":null,"video":null,"videoScope":"question","topic":"noun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"BtIlYgLiQx1L0Fp6m7gk","type":"short","question":"What is the plural form of the noun 'tooth'?","options":null,"answerIndex":null,"answer":"teeth","explanation":["Some nouns have irregular plural forms that do not simply add '-s' or '-es'. 'Tooth' becomes 'teeth'."],"hint":"","image":null,"video":null,"videoScope":"question","topic":"noun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"EhZlOm8eJ47I6N99dxOW","type":"short","question":"Name one abstract noun that describes a good quality someone can have.","options":null,"answerIndex":null,"answer":"kindness","explanation":["This tests the ability to recall an abstract noun that fits a specific description (a good quality)."],"hint":"","image":null,"video":null,"videoScope":"question","topic":"noun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"Opz9emLGhCxph5HYGa2V","type":"theory","question":"What is a noun? Give one example of a noun you might find in your classroom.","options":null,"answerIndex":null,"answer":"A noun is a word that names a person, place, animal, or thing. (Example: 'teacher', 'desk', 'school', 'book' - any valid noun from a classroom is acceptable).","explanation":["This question tests the basic definition of a noun and the ability to provide a relevant example."],"hint":"","image":null,"video":null,"videoScope":"question","topic":"noun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"eEo1pHzpjFpTto5FKWK6","type":"theory","question":"Read the sentence: 'My brother, Tom, loves to play with his toy car in the garden every Saturday.' Identify three nouns from this sentence and state whether each is a common noun or a proper noun.","options":null,"answerIndex":null,"answer":"Possible answers (any three with correct classification): 'brother' (common noun), 'Tom' (proper noun), 'car' (common noun), 'garden' (common noun), 'Saturday' (proper noun).","explanation":["This question assesses the ability to identify nouns within a sentence and correctly categorise them as either common (general names) or proper (specific names, capitalised)."],"hint":"","image":null,"video":null,"videoScope":"question","topic":"noun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"micAmstVcXQy33ycB4LO","type":"subjective","question":"A ____ of bees flew out of the hive.","options":null,"answerIndex":null,"answer":"swarm","explanation":["'Swarm' is a collective noun used to describe a group of bees."],"hint":"","image":null,"video":null,"videoScope":"question","topic":"noun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"sISKy80FbSiRCCqOLQ0G","type":"subjective","question":"My favourite pet is a fluffy white ____.","options":null,"answerIndex":null,"answer":"cat","explanation":["The missing word is a noun that names an animal, fitting the context of a pet."],"hint":"","image":null,"video":null,"videoScope":"question","topic":"noun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"xBtebDtcaGyBXGnhWY4f","type":"objective","question":"Which of these words is an abstract noun?","options":["table","happiness","teacher","cloud"],"answerIndex":1,"answer":null,"explanation":["Abstract nouns name ideas, feelings, or qualities that cannot be seen, touched, heard, smelled, or tasted. 'Happiness' is a feeling."],"hint":"","image":null,"video":null,"videoScope":"question","topic":"noun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"2mqbXxUC0htkJfM6Zbb0","type":"theory","question":"Explain the main difference between a common noun and a proper noun. Give an example for each.","options":null,"answerIndex":null,"answer":"A common noun names a general person, place, animal, or thing (e.g., 'boy', 'city'). A proper noun names a specific or particular person, place, animal, or thing (e.g., 'Tom', 'London'). Proper nouns always start with a capital letter.","explanation":["Understanding the distinction helps in correct capitalization and usage of nouns in sentences."],"hint":"Consider whether the noun refers to something general or something specific.","image":null,"video":null,"videoScope":"question","topic":"noun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"8rKFNM6hr2liy57pjZbZ","type":"objective","question":"Which word in the list below is an abstract noun?","options":["table","teacher","happiness","pencil"],"answerIndex":2,"answer":null,"explanation":["'Happiness' is an abstract noun because it refers to a feeling or state of being, not a physical object. 'Table', 'teacher', and 'pencil' are concrete nouns."],"hint":"An abstract noun names an idea, quality, or feeling that you cannot touch or see.","image":null,"video":null,"videoScope":"question","topic":"noun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"Efqr36u7m5EV3HqS8BDU","type":"short","question":"Name one collective noun that refers to a group of birds.","options":null,"answerIndex":null,"answer":"flock","explanation":["A 'flock' is a common collective noun for a group of birds. Other examples include 'flight' or 'colony' (for specific types of birds)."],"hint":"Many birds flying together form this group.","image":null,"video":null,"videoScope":"question","topic":"noun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"Gwzx7ppqcasbs43GONnj","type":"subjective","question":"My favourite toy is a shiny red ____.","options":null,"answerIndex":null,"answer":"car","explanation":["The blank requires a noun to name a thing (the toy). 'Car' is a suitable noun that fits the description."],"hint":"Think of a common toy that could be shiny and red.","image":null,"video":null,"videoScope":"question","topic":"noun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"XywM0OEvdYTBzn3Cqp7L","type":"polar","question":"Is 'Singapore' a common noun?","options":["Yes","No"],"answerIndex":1,"answer":null,"explanation":["'Singapore' is the name of a specific country, so it is a proper noun. Common nouns refer to general things (e.g., 'country')."],"hint":"Think about whether it names a specific place or a general place.","image":null,"video":null,"videoScope":"question","topic":"noun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"jcLkeSCLrR13WwjBb8XM","type":"subjective","question":"The proud _____ of lions rested under the shade of the acacia tree.","options":null,"answerIndex":null,"answer":"pride","explanation":["The collective noun for a group of lions is 'pride'."],"hint":"This is a specific collective noun for lions.","image":null,"video":null,"videoScope":"question","topic":"noun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"m5qudEyPiSQiBjE8N8fa","type":"short","question":"What is the plural form of the noun \"tooth\"?","options":null,"answerIndex":null,"answer":"teeth","explanation":["'Teeth' is the correct plural form of 'tooth'. This is an example of an irregular plural noun."],"hint":"This noun also has an irregular plural form, like 'foot' becomes 'feet'.","image":null,"video":null,"videoScope":"question","topic":"noun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"oLMMIUR1qHo1lK3zrZDw","type":"objective","question":"Which word in the sentence below is a noun?\\n\"The fluffy cat slept soundly on the soft rug.\"","options":["fluffy","slept","cat","soundly"],"answerIndex":2,"answer":null,"explanation":["'Cat' is the name of an animal, making it a noun. 'Fluffy' describes the cat (adjective), 'slept' is an action (verb), and 'soundly' describes how it slept (adverb)."],"hint":"A noun names a person, place, animal, or thing.","image":null,"video":null,"videoScope":"question","topic":"noun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"rdXQlQO0u4V4pLFfF06M","type":"polar","question":"To make the noun \"child\" plural, do you add an 's' at the end?","options":["Yes","No"],"answerIndex":1,"answer":null,"explanation":["No, 'child' has an irregular plural form, which is 'children'. Adding 's' would make it 'childs', which is incorrect."],"hint":"Some nouns have special plural forms.","image":null,"video":null,"videoScope":"question","topic":"noun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"vRc7Fw6vBb8svU5rg8hS","type":"theory","question":"Write two separate sentences. In the first sentence, use a common noun. In the second sentence, use a proper noun. Underline the noun in each sentence.","options":null,"answerIndex":null,"answer":"1. The <u>dog</u> barked loudly at the mailman.\\n2. <u>Sarah</u> went to the park with her friends.","explanation":["This question assesses the ability to identify and use different types of nouns correctly in context, including proper noun capitalisation."],"hint":"Remember to capitalise proper nouns and underline only the noun.","image":null,"video":null,"videoScope":"question","topic":"noun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"2TQK76J8ofymYkSaIplK","type":"subjective","question":"A group of fish swimming together is called a ____.","options":null,"answerIndex":null,"answer":"school","explanation":["'School' is a collective noun used to describe a group of fish."],"hint":"This is a special word used for a collection of fish.","image":null,"video":null,"videoScope":"question","topic":"noun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"3wUs34d2dUujfnLsh0wb","type":"short","question":"Rewrite the phrase 'the car belonging to my father' using a possessive noun.","options":null,"answerIndex":null,"answer":"my father's car","explanation":["To show possession for a singular noun, an apostrophe followed by 's' is added."],"hint":"You need to show ownership using an apostrophe.","image":null,"video":null,"videoScope":"question","topic":"noun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"ILdL3SH1IaRGs0rKjf7G","type":"theory","question":"Read the sentence below. List all the nouns you can find in it: 'The children saw a beautiful rainbow after the heavy rain.'","options":null,"answerIndex":null,"answer":"children, rainbow, rain","explanation":["'Children' is a common noun for people, 'rainbow' is a common noun for a thing, and 'rain' is a common noun for a natural phenomenon."],"hint":"Look for words that name people, things, or natural phenomena.","image":null,"video":null,"videoScope":"question","topic":"noun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"K8xj1ASFlxXzB4QwIOI5","type":"polar","question":"Can you count 'water' using numbers (e.g., one water, two waters)? Therefore, is 'water' a countable noun?","options":["Yes","No"],"answerIndex":1,"answer":null,"explanation":["'Water' is an uncountable noun because it cannot be counted individually. We use units like 'a glass of water' or 'litres of water' to quantify it."],"hint":"Think about whether you can put a number directly in front of the noun.","image":null,"video":null,"videoScope":"question","topic":"noun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"KoB3iTdK4nvurqVxc9rC","type":"objective","question":"Which of these nouns names something you cannot see, touch, hear, smell, or taste?","options":["cloud","friendship","sandwich","music"],"answerIndex":1,"answer":null,"explanation":["'Friendship' is an abstract noun, representing a quality or idea rather than a physical object. While you can hear 'music', 'friendship' itself is an intangible concept."],"hint":"Think about which word represents a feeling or an idea.","image":null,"video":null,"videoScope":"question","topic":"noun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"QdXFxijMz6BuTRw0UIHD","type":"polar","question":"Is the word 'city' a proper noun?","options":["True","False"],"answerIndex":1,"answer":null,"explanation":["'City' is a common noun because it refers to any city. A proper noun would be the specific name of a city, like 'Singapore' or 'Paris', and would be capitalized."],"hint":"Remember the rule about capitalization for proper nouns.","image":null,"video":null,"videoScope":"question","topic":"noun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"iYwJ6lPUPuINfAzsekaH","type":"short","question":"In the sentence: 'The curious kitten played with a colourful ball.', what is the noun that names an animal?","options":null,"answerIndex":null,"answer":"kitten","explanation":["'Kitten' is the noun referring to a young cat, which is an animal."],"hint":"Look for the word that refers to a living creature.","image":null,"video":null,"videoScope":"question","topic":"noun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"p64mfidbbNbbrz6Kr2Ut","type":"objective","question":"Choose the correct plural form for the noun 'mouse'.","options":["mouses","mice","mouse's","mouces"],"answerIndex":1,"answer":null,"explanation":["'Mice' is an irregular plural noun. Many common nouns have irregular plural forms that need to be learned."],"hint":"Some plurals do not follow the usual pattern of adding '-s' or '-es'.","image":null,"video":null,"videoScope":"question","topic":"noun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"sUV4vEtOKpAOpwZW1kBQ","type":"theory","question":"Imagine you are describing your classroom. Write one sentence about it, and then identify one common noun and one concrete noun from your sentence. (They can be the same word if applicable!)","options":null,"answerIndex":null,"answer":"Model Answer: 'Our classroom has many colourful posters on the wall.' Common Noun: 'posters' (or 'classroom', 'wall'). Concrete Noun: 'posters' (or 'classroom', 'wall').","explanation":["This question assesses the ability to construct a sentence and then correctly identify and classify nouns within it. Common nouns are general, while concrete nouns are tangible."],"hint":"A common noun names any general person, place, or thing. A concrete noun names something you can experience with your senses.","image":null,"video":null,"videoScope":"question","topic":"noun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"yM5t6DfGxowAgD6neckL","type":"objective","question":"Which of the following best describes what a noun names?","options":["An action or a doing word","A person, place, thing, or idea","A word that describes another word","A word that connects sentences"],"answerIndex":1,"answer":null,"explanation":["Nouns are fundamental words that name people, places, things, or abstract ideas."],"hint":"Think about what nouns refer to in the world around you.","image":null,"video":null,"videoScope":"question","topic":"noun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"4hCtFccYvcLh3khb1ChK","type":"subjective","question":"Fill in the blank with the correct pronoun: <br><br>\"Please give the book to ____. It belongs to her.\"","options":null,"answerIndex":null,"answer":"her","explanation":"'Her' is the correct object pronoun to use after the preposition 'to'.","hint":"","image":null,"video":null,"videoScope":"question","topic":"pronoun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"5GcJPg9uj275upBxhBKO","type":"objective","question":"Which word in the sentence below is a pronoun?\\n\\n\"My sister loves to read, and she often visits the library.\"","options":["sister","loves","she","library"],"answerIndex":2,"answer":null,"explanation":["'She' is a pronoun because it takes the place of 'My sister'."],"hint":"A pronoun replaces a noun.","image":null,"video":null,"videoScope":"question","topic":"pronoun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"Gw9QEKbSHlwY5A0e2TZO","type":"theory","question":"Write a short sentence using a possessive pronoun (e.g., mine, yours, ours).","options":null,"answerIndex":null,"answer":"That red ball is mine.","explanation":["Possessive pronouns show ownership without using an apostrophe (e.g., 'mine', 'yours', 'his', 'hers', 'ours', 'theirs')."],"hint":"","image":null,"video":null,"videoScope":"question","topic":"pronoun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"HcOgSFrzsvZjOzvz06UT","type":"objective","question":"Choose the correct pronoun to replace 'The dog' in the sentence:\\n\\n\"The dog wagged ____ tail excitedly.\"","options":["his","her","its","their"],"answerIndex":2,"answer":null,"explanation":["'Its' is the correct possessive pronoun for an animal when we don't specify gender, or when referring to something belonging to it."],"hint":"For animals, we often use a specific pronoun when we don't know their gender, or when referring to its possessions.","image":null,"video":null,"videoScope":"question","topic":"pronoun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"JCxf9tfdinkcT0wYEMGv","type":"short","question":"What kind of word takes the place of a noun to avoid repetition?","options":null,"answerIndex":null,"answer":"Pronoun","explanation":["Pronouns like 'he', 'she', 'it', 'they' help make sentences smoother by replacing nouns."],"hint":"","image":null,"video":null,"videoScope":"question","topic":"pronoun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"QjyLwQJ1JBKt8DANFQ1N","type":"objective","question":"Choose the best pronoun to complete the sentence:<br>\"My friends and I are going to the park. ____ will play football.\"","options":["He","She","They","We"],"answerIndex":3,"answer":null,"explanation":"Since the subject includes 'I' and others, 'we' is the correct pronoun.","hint":"Think about who 'My friends and I' refers to.","image":null,"video":null,"videoScope":"question","topic":"pronoun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"SN81OoB5wT9BgZAApnBX","type":"theory","question":"Explain in your own words why we use pronouns in our sentences.","options":null,"answerIndex":null,"answer":"We use pronouns to avoid repeating the same noun many times in a paragraph or conversation. It makes our sentences sound smoother and easier to read or listen to.","explanation":["Pronouns make writing and speaking more natural and less repetitive."],"hint":"","image":null,"video":null,"videoScope":"question","topic":"pronoun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"V4Bj9Gku05YPSdPSAKop","type":"subjective","question":"Fill in the blank with the correct pronoun:<br><br>\"Tom lost ____ pencil, so his friend shared one with him.\"","options":null,"answerIndex":null,"answer":"his","explanation":"'His' is a possessive pronoun that shows the pencil belongs to Tom.","hint":"","image":null,"video":null,"videoScope":"question","topic":"pronoun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"W1Sv1L3MEIusz5jPx6bX","type":"subjective","question":"Fill in the blank with the correct pronoun:\\n\\n\"He looked at ____ in the mirror after he brushed his teeth.\"","options":null,"answerIndex":null,"answer":"himself","explanation":["'Himself' is a reflexive pronoun, used when the subject and object of the verb are the same person."],"hint":"","image":null,"video":null,"videoScope":"question","topic":"pronoun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"vThfF15zy0ZYVu5dW45I","type":"polar","question":"Is the word 'tree' a pronoun?","options":["True","False"],"answerIndex":1,"answer":null,"explanation":["'Tree' is a noun, not a pronoun. A pronoun would replace a noun, like 'it'."],"hint":"","image":null,"video":null,"videoScope":"question","topic":"pronoun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"6pMjHWmaZ5g352jLAz9Z","type":"theory","question":"Explain the difference in meaning and usage between 'its' (without an apostrophe) and 'it's' (with an apostrophe). Give a short example sentence for each.","options":null,"answerIndex":null,"answer":"'Its' is a possessive pronoun or determiner used to show ownership by an animal or non-human object (e.g., 'The puppy wagged its tail'). 'It's' is a contraction short for 'it is' or 'it has' (e.g., 'It's raining outside').","explanation":["Primary 5 students often confuse these two homophones.","The apostrophe in 'it's' indicates a contraction (omitted letters), not possession."],"hint":"","image":null,"video":null,"videoScope":"question","topic":"pronoun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"9dz0X4Q3tQsQ10oYILIf","type":"short","question":"Identify the interrogative pronoun in the following question: 'Which of these books would you like to borrow from the library?'","options":null,"answerIndex":null,"answer":"Which","explanation":["An interrogative pronoun is used to ask a question.","Here, 'Which' stands in place of the chosen book and asks the reader to make a selection."],"hint":"","image":null,"video":null,"videoScope":"question","topic":"pronoun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"AjxfxIii1VTCIJNAGkLM","type":"objective","question":"Choose the pronoun that correctly completes the sentence: 'The teacher praised Sarah and ____ for finishing the group project so quickly.'","options":["I","me","myself","we"],"answerIndex":1,"answer":null,"explanation":["The pronoun acts as the object of the verb 'praised'.","By removing 'Sarah and', we get 'The teacher praised me', which is grammatically correct.","'The teacher praised I' is incorrect because 'I' is a subject pronoun."],"hint":"Remove 'Sarah and' from the sentence to see which pronoun sounds correct on its own.","image":null,"video":null,"videoScope":"question","topic":"pronoun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"OTApIfKghPqcQbNjpHaK","type":"polar","question":"In the sentence 'Those apples are ripe, but these are rotten,' the word 'these' is acting as a demonstrative pronoun.","options":["True","False"],"answerIndex":0,"answer":null,"explanation":["In this sentence, 'these' stands alone and replaces the noun phrase 'these apples', making it a demonstrative pronoun.","In contrast, 'Those' is acting as a demonstrative adjective because it is directly followed by the noun 'apples'."],"hint":"","image":null,"video":null,"videoScope":"question","topic":"pronoun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"QO2dJY3GZOgRxCwWBL8h","type":"polar","question":"In the sentence 'The bicycle who has a flat tire belongs to Uncle Jim', the relative pronoun 'who' is used correctly.","options":["True","False"],"answerIndex":1,"answer":null,"explanation":["The relative pronoun 'who' is only used to refer to people.","Since a bicycle is an inanimate object, we should use 'which' or 'that' instead of 'who'."],"hint":"","image":null,"video":null,"videoScope":"question","topic":"pronoun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"RSRAYeZvQh1JbtseZ9Q9","type":"short","question":"In the sentence 'That blue bicycle is mine, but you can ride your skateboard,' which word is a possessive pronoun?","options":null,"answerIndex":null,"answer":"mine","explanation":["'mine' is a possessive pronoun because it replaces the noun phrase 'my bicycle' and stands alone.","'your' is a possessive adjective (determiner) because it is followed directly by the noun 'skateboard'."],"hint":"","image":null,"video":null,"videoScope":"question","topic":"pronoun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"Sr7deES8tVMEwYn9sA0r","type":"subjective","question":"After a long afternoon of playing in the muddy park, the twin puppies cleaned ____ by licking their paws.","options":null,"answerIndex":null,"answer":"themselves","explanation":["The subject 'the twin puppies' is plural (they).","Therefore, the matching reflexive pronoun to show they performed the action on themselves is 'themselves'."],"hint":"","image":null,"video":null,"videoScope":"question","topic":"pronoun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"cVh7xSJot1iVxIE9Wwbs","type":"objective","question":"Choose the correct pronoun to complete the sentence: 'This secret is strictly between you and ____, so please do not tell anyone else.'","options":["I","me","myself","we"],"answerIndex":1,"answer":null,"explanation":["The word 'between' is a preposition, which must be followed by an object pronoun.","'Me' is the object pronoun, whereas 'I' is a subject pronoun.","A good trick is to try the sentence with just the pronoun: you would say 'between me', not 'between I'."],"hint":"Think about whether you need a subject pronoun or an object pronoun after the preposition 'between'.","image":null,"video":null,"videoScope":"question","topic":"pronoun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"fl4fS8DwR4kums1L6WgN","type":"objective","question":"Complete the sentence with the correct pronoun: 'Either the captain or the players must give ____ statement to the reporters after the match.'","options":["his","their","its","them"],"answerIndex":1,"answer":null,"explanation":["In a compound subject joined by 'either... or', pronoun-antecedent agreement rules state that the pronoun must agree with the closest noun.","The closest noun is 'players' (plural), so we use the plural possessive pronoun 'their'."],"hint":"When subjects are joined by 'either... or', the pronoun agrees with the closer noun.","image":null,"video":null,"videoScope":"question","topic":"pronoun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"},{"id":"nOaadnNPkP8IB5gVvYkT","type":"subjective","question":"The student ____ poster won first prize in the art competition was congratulated by the principal.","options":null,"answerIndex":null,"answer":"whose","explanation":["We need a relative pronoun that shows possession of the poster by the student.","'whose' is the possessive relative pronoun used for this purpose."],"hint":"","image":null,"video":null,"videoScope":"question","topic":"pronoun","classLevel":"grade7","scheme":"practice","subject":"english","subjectLabel":"English Language","grade":"Grade 7"}];
